package dev.aperture.editor.imgui;
import dev.aperture.editor.model.history.EditorHistoryEntry;import dev.aperture.editor.model.read.EditorDiagnostic;import imgui.ImGui;
final class ActivityConsoleWindow{private final ApertureUiContext c;ActivityConsoleWindow(ApertureUiContext c){this.c=c;}void render(){if(!ImGui.begin("Activity Console")){ImGui.end();return;}if(ImGui.beginTabBar("ActivityTabs")){if(ImGui.beginTabItem("History")){c.session.history().designCommands().forEach(this::history);ImGui.endTabItem();}if(ImGui.beginTabItem("Events")){c.session.history().runtimeEvents().forEach(this::history);ImGui.endTabItem();}if(ImGui.beginTabItem("Diagnostics")){c.session.diagnostics().all().forEach(this::diagnostic);ImGui.endTabItem();}tab("Network");tab("Performance");ImGui.endTabBar();}ImGui.end();}private void history(EditorHistoryEntry e){ImGui.bulletText(e.summary()+"   r"+e.revision()+"   "+e.result());}private void diagnostic(EditorDiagnostic d){float[] color=d.severity()==EditorDiagnostic.Severity.ERROR?ApertureStyle.ERROR:d.severity()==EditorDiagnostic.Severity.WARNING?ApertureStyle.WARNING:ApertureStyle.BLUE;ImGui.textColored(color[0],color[1],color[2],1,d.severity()+"   "+d.code()+"   "+d.message());}private static void tab(String label){if(ImGui.beginTabItem(label)){ImGui.textDisabled(label+" telemetry is not connected");ImGui.endTabItem();}}}
